import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,

  Select,
  LinPageLayout,
  dispatchAppToast,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { EmployeeDto, PieceRateLedgerRow } from '../../../services/ns/models';
import { soLuongKhoanPageLabels as labels } from '../../../constants/soLuongKhoanPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrPieceRateLedgerPermissions } from '../../../hooks/useHrPermissions';
import { formatVnd } from '../../../utils/format';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-luong-khoan';
const PAGE_ID = 'ns-so-luong-khoan';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `T${i + 1}`,
}));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

const SoLuongKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useHrPieceRateLedgerPermissions();
  const now = new Date();
  const [reloadKey, setReloadKey] = useState(0);
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [employeeId, setEmployeeId] = useState('');
  const [employees, setEmployees] = useState<EmployeeDto[]>([]);
  const [rows, setRows] = useState<PieceRateLedgerRow[]>([]);
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
  }, []);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getEmployees({ type: 'PieceRate', isActive: true, pageSize: 200 })
        .then(res => {
          if (!cancelled) setEmployees(res.items);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getPieceRateLedger({ month, year, employeeId: employeeId || undefined })
        .then(data => {
          if (!cancelled) setRows(data);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, month, year, employeeId, reloadKey]);

  const totalAmount = rows.reduce((s, r) => s + (r.totalAmount ?? 0), 0);

  const handleExport = useCallback(() => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    if (employeeId) qs.set('employeeId', employeeId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/piece-rate-ledger/export-excel?${qs}`;
    a.download = `LuongKhoan-T${month}-${year}.xlsx`;
    a.click();
  }, [month, year, employeeId]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(
    () =>
      rows.length > 0
        ? `${labels.summaryTotal}: ${formatVnd(totalAmount)} · ${rows.length} ${labels.itemLabel}`
        : undefined,
    [rows.length, totalAmount],
  );

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        onClick: refresh,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];
    if (!perms.canRead) return left;
    return [
      ...left,
      {
        id: 'export',
        placement: 'right',
        label: labels.exportAction,
        variant: 'secondary',
        visible: true,
        disabled: rows.length === 0,
        onClick: handleExport,
        testId: `${TEST_ID}-toolbar-export-btn`,
      },
    ];
  }, [refresh, perms.canRead, handleExport, rows.length]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={refresh}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select
                label={labels.monthLabel}
                value={String(month)}
                onChange={e => setMonth(Number(e.target.value))}
                options={MONTH_OPTIONS}
                fullWidth
              />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select
                label={labels.yearLabel}
                value={String(year)}
                onChange={e => setYear(Number(e.target.value))}
                options={YEAR_OPTIONS}
                fullWidth
              />
            </div>
            <div data-testid={`${TEST_ID}-field-employee`}>
              <Select
                label={labels.employeeLabel}
                value={employeeId}
                onChange={e => setEmployeeId(e.target.value)}
                options={[
                  { value: '', label: labels.employeeAll },
                  ...employees.map(e => ({ value: e.id, label: e.fullName })),
                ]}
                fullWidth
              />
            </div>
          </>
        )}
      />
    ),
    [month, year, employeeId, employees, refresh, showTableLoading],
  );

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colEmployee}</th>
              <th>{labels.colStage}</th>
              <th className={erp.colRight}>{labels.colQty}</th>
              <th className={erp.colRight}>{labels.colPrice}</th>
              <th className={erp.colRight}>{labels.colAmount}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => (
              <tr key={`${r.employeeId}-${r.stageName}-${i}`} data-testid={`${TEST_ID}-row-${i}`}>
                <td>{r.employeeName ?? '—'}</td>
                <td>{r.stageName ?? '—'}</td>
                <td className={erp.colRight}>{r.totalQty ?? 0}</td>
                <td className={erp.colRight}>{formatVnd(r.pricePerUnit ?? 0)}</td>
                <td className={erp.colRight}>
                  <strong>{formatVnd(r.totalAmount ?? 0)}</strong>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-chart-bar',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoLuongKhoanPage;
